'use client';

import React, { useState } from 'react'

import Image, { ImageProps } from 'next/image'

const ERROR_IMG_SRC =
  'data:image/svg+xml;base64,'

export function ImageWithFallback(props: Omit<ImageProps, 'fill' | 'onError'>) {
  const [didError, setDidError] = useState(false)

  const handleError = () => {
    setDidError(true)
  }

  const { src, alt, style, className, ...rest } = props

  return didError ? (
    <div
      className={`inline-block bg-gray-100 text-center align-middle relative ${className ?? ''}`}
      style={style}
    >
      <div className="flex items-center justify-center w-full h-full relative">
        <Image src={ERROR_IMG_SRC} alt="Error loading image" fill className="object-contain" />
      </div>
    </div>
  ) : (
    <div className={`relative ${className ?? ''}`} style={style}>
      <Image src={src} alt={alt || 'Image'} fill className="object-cover" {...rest} onError={handleError} />
    </div>
  )
}
